export const findCdslDpId = (id: string) => {
  if (!id || id.length < 8) return undefined;
  // First 8 digits (CDSL BO format: DP_ID + Client_ID)
  const firstBatch = id.slice(0, 8);
  const dp = cdslDp.find((e) => firstBatch.includes(e["DP ID"]));
  return dp?.["DP Name"];
};

/** Exact match by DP ID (for numeric DP IDs from settlement). */
export const findCdslDpByDpId = (dpId: string) => {
  if (!dpId || !String(dpId).trim()) return undefined;
  const id = String(dpId).trim();
  const dp = cdslDp.find((e) => e["DP ID"] === id);
  return dp?.["DP Name"];
};
